import type { BourbonPageDepth } from './types';

export const BOURBON_PAGE_DEPTH_TOOLS: BourbonPageDepth[] = [
  {
    id: 'producers',
    path: '/bourbon/producers',
    title: "Producer Atlas",
    openingNarrative: `Every bottle is a letter from a house — not always the house on the label, which is why investigators read DSP numbers like return addresses before they trust a story. The Producer Atlas is twelve distilleries worth knowing cold: who they are, what they default to in the glass, where their sweet spot lives on the shelf, and which questions still split their fanbases at midnight on forums. Buffalo Trace is not just Pappy mythology — it is a campus where wheated and high-rye recipes share rickhouse air and allocation drama. Heaven Hill is not just value BiB — it is a family story tied to Bardstown smoke and labels you have seen a thousand times without knowing they share a roof. Maker's Mark is not just red wax — it is a deliberate proof and yeast choice you can taste blind if you pay attention. This atlas is written for stewards who want producer literacy, not logo collection — the kind of literacy that collapses an aisle from chaos into choices.`,
    whyItMatters: `Producer knowledge collapses the aisle faster than any score app. When you know what a house defaults to — wheated softness, high-rye spice, consistent BiB value, experimental finishes — you stop rebuying the same flavor in different bottles and start choosing intentionally for gaps on your shelf. You also spot contract sourcing and shared campuses before marketing tells you a fairy tale about craft independence. Houses become characters with habits, not stickers with hype cycles. That shift saves money, improves blind nights, and makes tours worth the drive because names on walls mean something when you walk rickhouses. Producer literacy is how you stop paying for the same house five times in different costumes — the aisle finally starts feeling navigable.`,
    beginnerMisunderstanding: `Beginners think brand equals distillery equals taste — one logo, one juice, one profile forever. Contract sourcing, shared campuses, different mash bills inside one company, and NDP brands break that assumption weekly. The atlas teaches houses and production habits, not front-label romance. Two bottles can look like competitors and share a still, or look like siblings and taste nothing alike because mash bill and barrel strategy diverged. Learning producers is how you stop being surprised by sameness and start being delighted by intentional differences you chose on purpose. NDP and shared stills are not edge cases — they are Tuesday in American whiskey, and the atlas teaches you to read them without cynicism or naivety.`,
    realWorldExample: `You see two bottles at $40 — one Beam family expression, one craft label with local art and a story about small batches. Atlas tells you Beam's default profile and what the craft house might be buying from where. You choose based on a gap in your shelf — you need rye spice, not another wheated soft pour — and skip the pretty label that would have duplicated last month's purchase. At home you log the bottle, run shelf intel, and the app confirms you finally have balance. The atlas turned a coin flip into a curriculum you picked. Next tasting, name the house behind two bottles before revealing labels — producer literacy turns party tricks into real teaching moments.`,
    howToUse: `Pick a producer you keep buying unconsciously because it is always there — Buffalo Trace, Heaven Hill, Wild Turkey, whatever your aisle repeats. Read sweet spot and hidden question sections fully, not just the headline bottle. Click into producer profile for campus and bottle links when you want place-based context. Add one bottle from that house you have never tried, ideally one rung up or sideways on mash bill, not the same expression in a new label. Revisit when detective cases mention DSP numbers tied to that house. Pick the house on your shelf with the most bottles and read its hidden question aloud — if you cannot answer it, that is your homework before the next purchase.`,
    whatToNoticeNext: `Cross-reference with Detective DSP case and campus maps — producers become places with floors, chars, and climates, not names on trivia cards. When you tour, ask questions the atlas seeded. When you shop, notice which houses dominate your shelf and whether that dominance is habit or identity. If one producer exceeds fifty percent of your collection, you are loyal — or stuck. The atlas helps you tell which. When DSP cases and atlas entries align, you are reading bourbon like a document — keep campus maps open for the same house and taste geography on purpose. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    rabbitHoles: [
      { label: "Buffalo Trace profile", href: '/bourbon/producers/buffalo-trace' },
      { label: "Campus maps", href: '/bourbon/campus' },
      { label: "Distillery wars", href: '/bourbon/wars' },
    ],
  },
  {
    id: 'beyond-the-bottle',
    path: '/bourbon/beyond-the-bottle',
    title: "Beyond the Bottle",
    openingNarrative: `Bourbon did not stay in Kentucky. It walked into movies, sat beside presidents, sound-tracked jazz clubs, and borrowed its name from a street that may never have sold a drop of whiskey to the tourists who photograph it anyway. To love bourbon only as liquid is to miss half the hobby — the stories people tell while pouring, the trips planned around rickhouses, the playlist that makes a Tuesday pour feel like an occasion worth dressing up for. Beyond the Bottle is the cultural orbit: origins that are stranger than marketing slogans, pop moments that sent bottles flying off shelves overnight, pour guides that respect both craft and chaos, and connection graphs that show how bourbon touches barbecue, politics, travel, and music without asking permission. Read here when you want to feel the category as a world you belong to, not a SKU you chase — when you want context that makes the next pour mean something beyond proof and price.`,
    whyItMatters: `Culture sustains obsession when prices frustrate you and allocations insult your calendar. Knowing why bourbon shows up in film, Derby traditions, or Prohibition lore gives you stories for the table — and stories keep people hosting when trophies disappoint. Hosts who connect juice to context create emotional memory that bottles alone cannot. Culture also lowers the bar for newcomers who think whiskey is a performance. One true story plus one thoughtful pour beats ten mash bill percentages shouted over ice clinking. This section keeps the hobby human when markets try to make it purely financial. Culture is not the side quest — it is often the reason someone accepts a second pour when proof alone would have ended the night early.`,
    beginnerMisunderstanding: `People think culture content is filler compared to tasting — optional wallpaper until you are "serious." In practice, hosts who tell one true story per pour create more bourbon fans than hosts who recite fermentation facts without knowing their audience. Culture is not opposite to skill; it is the bridge that makes skill welcome. Beginners often arrive through a movie, a trip, a gift — not a flavor wheel. Meeting them where they entered honors how the hobby actually spreads, not how forums pretend it spreads. Guests rarely ask for mash bills first — they ask for a story that makes the glass feel welcome, and that is a host skill worth building deliberately.`,
    realWorldExample: `You pour for skeptics who "don't like whiskey" because last year's party burned them with harsh neat pours and mansplaining. You tell the Prohibition medical exemption story briefly, serve on a rock without apology, and pair with dark chocolate because fat tames heat. They ask where to buy a bottle Monday — not because you impressed them with proof, because you made bourbon feel like culture instead of exam. You send them to Level 1, not a top-100 list. Culture opened the door; juice kept them when they bought BiB that week. The skeptic who buys BiB on Monday did not convert to whiskey religion — they converted to curiosity, which is how every steward actually starts.`,
    howToUse: `Browse by mood — origins for history nerds, pop culture for party hosts, pour guide before guests arrive, where-to-buy before a trip, connections when you want to wander without a plan. One essay plus one tool per visit beats bingeing ten tabs you will forget. Save one story to retell verbatim at your next host night — rehearsal matters. Link culture reads to a bottle you actually own so the story has a pour attached, not abstract enthusiasm. Before guests arrive, pick one story and one bottle that proves it — rehearsal keeps you from rambling and lets the pour land when the room gets quiet.`,
    whatToNoticeNext: `Follow connections graph from bourbon to music or food — identity tracks (host, traveler, historian) live here and show up again in personalities tools. When pop culture sends you to a bottle spike, pair with economy page so you understand price as story plus supply, not just hype. If you keep returning to origins, plan a trip segment around places, not only distilleries. If connections graph keeps pulling you toward music or food, plan one dinner pour around that node — identity tracks love behavior, not declarations. That is stewardship in practice — attention, context, and a pour that proves you paid both. Barrel char taught you wood matters; this page teaches you everything else around the glass matters too.`,
    rabbitHoles: [
      { label: "Origins map", href: '/bourbon/origins' },
      { label: "Pop culture", href: '/bourbon/pop-culture' },
      { label: "Pour impact guide", href: '/bourbon/pour-guide' },
    ],
  },
  {
    id: 'lore',
    path: '/bourbon/lore',
    title: "World Lore",
    openingNarrative: `Every bourbon worth loving has a ghost story — a master distiller who outlasted trends, a rivalry that split a town, a bottle that became religion without tasting better than its siblings on a blind table. Lore is where Foundry keeps mythology on purpose: not fake history, but the narratives that make people drive hours for a tour, camp overnight for a release, or inherit a decanter they will never open because opening it would end the story. Heroes, legends, debates, mysteries, pilgrimages, and legendary objects live here the way saints and folktales live in older cultures — imperfect, argued over, alive. You read lore to feel belonging — to know why people argue about wheated mash at 2 a.m., why rickhouse fires still haunt insurance conversations, why a red wax dip signals something even when you prefer another house entirely. Lore is how bourbon stops being a transaction and starts being a culture you can enter without a gatekeeper exam.`,
    whyItMatters: `Mythology drives return visits when spreadsheets cannot. When a world has stories, daily hooks and detective cases land harder because they plug into characters and rivalries you already care about emotionally, not just intellectually. Lore also teaches incentives — why brands lean on legacy, why communities form around scarcity, why tours sell labor as romance. Understanding those incentives makes you harder to manipulate in aisles while still enjoying the romance honestly. Stories are data about culture, not distractions from juice. Characters and rivalries make market noise legible — when you know why a crowd cares, you can host the argument without owning every bottle mentioned.`,
    beginnerMisunderstanding: `Beginners dismiss lore as marketing fluff distilleries invented yesterday. Distilleries do market — but the best lore is crowd-tested truth stretched into narrative: rivalries reflect real production differences; legends encode real labor, loss, and luck; pilgrimages point at places where process is visible. Dismissing all lore loses the map; swallowing all lore loses the skepticism. Stewardship holds both — enjoy the story, verify the pour, argue when myth and glass disagree. Legend without verification is marketing; legend with verification is culture — stewards learn to hold both in the same hand without spilling either. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    realWorldExample: `You tour Bardstown and recognize names from lore pages — the guide's story overlaps Foundry's legend entry enough that you nod, but you also notice where tour script smooths rough history. You ask a sharper question in the rickhouse about fire recovery and barrel char because lore warned you fires are not ancient history. The guide answers differently when you sound informed, not performative. The tour becomes pilgrimage — you bought context before miles, not souvenirs after. Ask your tour guide one lore-inspired question that is not on the script — informed curiosity gets better answers than fanboy performance ever does. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    howToUse: `Start with debates if you like arguments, legends if you like people, mysteries if you are detective-minded, pilgrimages if you are planning travel. One story per session — lore rewards slow reading like bourbon rewards slow sips. Follow links into producer atlas and detective cases when names repeat; repetition is the graph connecting story to system. Retell one legend at your next pour without reading from your phone — memory is stewardship. Read one legend, then pour one accessible bottle tied to it — story plus glass beats story alone every time for memory and for guests. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    whatToNoticeNext: `Compare lore debates to Watchtower signals — when culture and market align, you are seeing a live moment worth hosting around. When legend and detective case disagree, trust the case file first, then ask why the legend persists anyway — often marketing, sometimes deeper truth about identity. Track which heroes you reference twice; that is your unconscious brand loyalty showing up for inspection. When Watchtower and lore name the same rivalry, pour both sides blind if you can — mythology becomes evidence when palates pick winners without labels. That is stewardship in practice — attention, context, and a pour that proves you paid both. Barrel char taught you wood matters; this page teaches you everything else around the glass matters too.`,
    rabbitHoles: [
      { label: "Bourbon universe map", href: '/bourbon/universe' },
      { label: "History stories", href: '/bourbon/stories' },
      { label: "Detective cases", href: '/bourbon/detective' },
    ],
  },
  {
    id: 'pour-guide',
    path: '/bourbon/pour-guide',
    title: "Pour Impact Guide",
    openingNarrative: `The same bourbon can taste like two different spirits depending on what you do after the pour — and most arguments about "good bourbon" are secretly arguments about serve temperature, dilution, and glass without anyone naming those variables. Neat concentrates proof and exposes flaws alongside virtues. A large ice ball dilutes slowly and can mute heat while opening vanilla that hid behind ethanol. A splash of water can unlock fruit that barrel proof masked like a shy guest at a loud party. Cola is not a sin — it is a different instrument, and pretending otherwise is snobbery, not stewardship. This guide walks serve choices like a knowledgeable friend at your counter: what each method emphasizes, what it hides, when it flatters cheap bottles, when it wastes special ones, and when context — porch, fire, party — matters more than rules. You will not find performance art here. You will find reasons that improve your next Tuesday.`,
    whyItMatters: `Serve is the cheapest upgrade in bourbon before you buy another bottle chasing a problem serve created. Temperature, dilution, glass shape, and pacing between sips change perception more than many $30 label swaps. Hosts who adjust serve rescue bottles they almost hated and stop apologizing for pours that were fine but mistreated. Guests who only " dislike whiskey" often dislike proof delivery, not flavor — fix serve before fixating on mash bill. Money saved on redundant bottles funds trips, blind nights, and BiB staples that teach faster. Serve knowledge rescues bottles from unfair trials — most "bad pours" are mismatched context, not bad juice, and fixing context is free.`,
    beginnerMisunderstanding: `Beginners think "proper bourbon" must be neat room-temp in a Glencairn or you failed some invisible test administered by strangers online. Context matters more than dogma — hot porch afternoons, winter fires, cocktail parties, structured tasting flights each demand different choices and none require apology. Water is a tool, not an admission of weakness. Ice is a timer for dilution, not automatically barbarism. The guide exists to free you from performance and improve what is already on your shelf tonight. Glencairns are tools, not morality — the right serve is the one that makes tonight's bottle honest for you and your guests, full stop. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    realWorldExample: `You have a high-proof pick that tastes like fire neat — you almost listed it in a local group, almost blamed the barrel. Two drops of water and it becomes strawberry jam and baking spice; you almost traded away your favorite bottle of the year because serve was wrong, not juice. You pour the same bottle two ways at a tasting — neat for heat lovers, lightly diluted for you — same label, zero shame. Serve knowledge saved $60 and a friendship that would have heard you complain about a bottle that was fine all along. The friend who hated the fire neat pour loves the same bottle with water — you did not change the whiskey, you changed the conversation it could have.`,
    howToUse: `Pick the scenario closest to tonight — solo sip, guests arriving in an hour, cocktail curiosity, gift bottle you fear wasting. Read one section fully instead of skimming all modes at once. Pour once exactly as described, take one sip, adjust, take another. Compare one sip before and after dilution with the same bottle so cause and effect stick. Note which mode you default to habitually — habit is data about palate and context, not destiny. Keep a small water dropper or pitcher near the bar — visible permission to dilute beats hidden shame and improves almost every high-proof night. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    whatToNoticeNext: `Pair with blind games — serve changes are easier to taste when labels are hidden and ego is lower. Revisit after lab sliders if proof still fights you — sometimes the fix is water, sometimes the fix is buying lower proof intentionally. If guests ask for rocks every time, build a guest-pour section on your shelf instead of fighting them with neat lectures. If blind games change your preferred serve for a bottle, update your shelf notes — serve is part of the bottle's identity once you log it honestly. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    rabbitHoles: [
      { label: "Pairing engine", href: '/bourbon/pairings' },
      { label: "Blind tasting games", href: '/bourbon/games' },
      { label: "Bourbon myths", href: '/bourbon/myths' },
    ],
  },
  {
    id: 'where-to-buy',
    path: '/bourbon/where-to-buy',
    title: "Where to Buy",
    openingNarrative: `Finding bourbon is its own hobby — especially now when allocation, interstate shipping law, tourist seasonality, and influencer drops reshape shelves weekly without warning. Kentucky is not the only pilgrimage; NYC bodegas hide surprises, Texas builds bourbon bars faster than rickhouses age juice, online retailers flash sales at midnight, and your local grocery might quietly carry a BiB gem next to the wine nobody talks about. This guide is regional honesty: where hunters actually score staples, where tourists overpay for the same bottle they could find at home, how to read a store's pick program before you trust the sticker, when travel beats shipping after fees and breakage, and why befriending one clerk beats refreshing fifty Discord tabs while hating yourself. It will age — markets move — but principles of place, relationship, and label literacy stay stable even when the hottest store changes names. Hunting smarter beats hunting harder every time.`,
    whyItMatters: `Money and time spent hunting badly is money not spent tasting — and tasting is where stewardship forms, not rumor threads. A steward builds two or three reliable sources instead of chasing every lead, learns which regions reward relationship shopping, and stops treating empty shelves as personal failure. Travel plans improve when you know which stops are tourism traps versus suburban goldmines thirty minutes away. Online buying gets safer when you understand shipping law and which retailers actually move inventory instead of hoarding hype. Two reliable stores beat fifty rumor tabs — hunting literacy is mostly subtraction, removing dead ends until what remains is worth your Saturday.`,
    beginnerMisunderstanding: `Beginners think bourbon deserts are hopeless forever or that Kentucky solves everything if you fly once. Both are wrong in ways that cost people trips and dignity. Value and variety exist in surprising channels — grocery chains, state stores, border counties, online flash sales — if you know what to look for on the label instead of the hype sticker. Kentucky can be picked clean on tourist strips while locals shop elsewhere. Your hometown may already have BiB; you just have not learned which day deliveries land. Empty local shelves often mean wrong day or wrong store type, not personal failure — relationship and timing beat geography myths most weeks.`,
    realWorldExample: `You visit Louisville assuming shelves are gold because social media said so. Lore and this guide remind you tourists compete with locals on famous strips. You drive thirty minutes to a suburban store on a weekday, find BiB staples at MSRP, and spend tourist savings on one distillery tour with a real question about char. Trip saved, ego intact, suitcase not full of markup you regret at baggage claim. You log stores in notes for next year instead of relying on memory. Write down the suburban store name for next year's trip before you forget — successful hunts should become traditions, not one-off miracles you cannot repeat.`,
    howToUse: `Read your region first — where you live dictates law, pricing, and allocation habits more than forum wisdom from another state. Then travel sections if planning a trip; cross-check economy page for why prices differ when the same bottle crosses a border. Build a short list of three stores to visit monthly, not fifty to FOMO browse on apps. Introduce yourself to one clerk with a specific question about picks — relationships start small. Update your list when a hunt succeeds; patterns beat generic guides. Call one store and ask when BiB deliveries land — clerks remember polite regulars faster than strangers who only show up for unicorns.`,
    whatToNoticeNext: `Log finds in My Bourbon Shelf — patterns in your successful hunts teach more than any guide update written for everyone. When economy explains a price you saw regionally, link the two insights. If online beats local for you after fees, own that workflow instead of performing local loyalty. Where-to-buy is strategy, not identity. Shelf logs reveal your real hunting pattern over months — trust that data more than any guide update written for a national audience. That is stewardship in practice — attention, context, and a pour that proves you paid both. Barrel char taught you wood matters; this page teaches you everything else around the glass matters too.`,
    rabbitHoles: [
      { label: "Bourbon economy", href: '/bourbon/economy' },
      { label: "Trail planner", href: '/bourbon/trail-planner' },
      { label: "Store pick academy", href: '/bourbon/store-picks' },
    ],
  },
  {
    id: 'economy',
    path: '/bourbon/economy',
    title: "Bourbon Economy",
    openingNarrative: `Price tags are emotional arguments written in numbers — and bourbon shelves in 2026 are loud with arguments nobody agreed to have. MSRP is what a brand wishes the world believed about fairness. Shelf price is what a store thinks you will pay today given allocation and rent. Secondary price is what panic and FOMO agree on when lottery systems fail and social media rewards screenshots over sips. Bourbon economy is not abstract macro — it is the reason your friend found Eagle Rare at $42 and you saw $139, why store picks suddenly cost double, why distilleries pretend not to notice secondary markets while benefiting from hype that makes MSRP feel like a joke. This page explains allocation tiers, state law quirks, tourist markup, account relationships, and when you are paying for juice versus lottery tickets dressed as whiskey. Read it when you are angry at a shelf tag — anger without structure becomes superstition; anger with structure becomes strategy you can teach friends without sounding bitter.`,
    whyItMatters: `Financial stewardship is bourbon stewardship — overspending on trophies while ignoring BiB staples is the most common regret in the hobby once the glow fades. Economy literacy frees budget for experiences that actually build palate and memory: trips, host nights, blind compares, one intentional splurge instead of three panic buys. It also reduces shame — empty shelves are often systems, not personal failure. When you understand incentives, you spend less energy hating clerks and more energy choosing battles worth fighting, bottles worth opening, and prices worth walking past. Understanding price protects joy — you can love bourbon without financing hype, and economy literacy is how that balance stays sustainable for years.`,
    beginnerMisunderstanding: `Beginners assume high price equals quality because expensive things usually signal quality in other categories — wine taught many people that lesson wrong for whiskey. Secondary markets decouple price from palate after a point; marketing decouples story from juice daily. Many $35 bottles outpour $200 trophies in blind settings that do not read Instagram. Expensive can be great; expensive is not automatically better. Economy page exists to separate value, hype, scarcity theater, and genuine craft differences without pretending cheap always wins — context matters. Secondary prices measure panic as often as quality — the glass still decides, and blind nights exist precisely to remind you of that humbling fact.`,
    realWorldExample: `You almost bought a marked-up pick because the tag said "barrel select" and the clerk implied scarcity. Economy section explains account tiers, MSRP bands, and pick markup psychology in plain language. You buy standard expression plus two BiB bottles instead at the same spend — same evening, triple learning, zero regret post. Next month you close a detective case that references the same incentives and feel the framework click permanently. You did not become cheap. You became literate. Teaching one friend why MSRP and shelf price diverged cements your own learning faster than rereading the same paragraph alone at midnight. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    howToUse: `Read allocation and MSRP sections before big purchases — over $60, limited stickers, travel impulse aisles. Use detective cases as narrative case studies so numbers attach to stories you remember. Revisit after closing Weller or Eagle Rare investigations when emotions are fresh but structured. Pair with where-to-buy when travel shopping tempts you — tourist markup has patterns. Argue with one friend about a price you saw; teaching locks learning. Screenshot outrageous tags once, then read the allocation section with coffee — anger fades when structure appears, and structure becomes strategy. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    whatToNoticeNext: `Watchtower controversial bottle signal often ties here — when market and culture fight, economy explains why without choosing sides for you. If you notice your spend rising while satisfaction flatlines, rerun shelf intel and economy together — often you are buying lottery tickets, not learning bottles. Track one price you walked past and why; pride in walking away is stewardship too. When spend rises but smiles do not, economy plus shelf intel together usually reveal lottery buying — correct one gap before the next release noise arrives. That is stewardship in practice — attention, context, and a pour that proves you paid both. Barrel char taught you wood matters; this page teaches you everything else around the glass matters too.`,
    rabbitHoles: [
      { label: "Weller detective case", href: '/bourbon/detective/weller-ghost' },
      { label: "Store pick academy", href: '/bourbon/store-picks' },
      { label: "Watchtower", href: '/bourbon/watchtower' },
    ],
  },
  {
    id: 'shelf-builder',
    path: '/bourbon/shelf-builder',
    title: "Shelf Builder",
    openingNarrative: `A bourbon shelf is a autobiography written in glass — and most autobiographies start messy before they find a voice worth rereading. Beginner shelves repeat the same profile because recommendations echo: one wheated, one spicy, one bottle someone swore by at a wedding. Collector shelves tell arcs — BiB chapter, single barrel experiments, travel exclusives, empty bottles kept for memory not clutter. Shelf Builder asks budget and ambition honestly, then proposes a small set of bottles with roles: daily pour, guest impresser, learning bottle, wild card that might fail beautifully. It is not an algorithm pretending to know your palate better than you will after three pours. It is a steward's worksheet — the same conversation a good friend would have before you blow $200 on three nearly identical mash bills because labels looked different under fluorescent lights. Build starter, advanced, or collector tracks knowing you can revise after every blind game and detective case closes.`,
    whyItMatters: `Shelf coherence beats shelf size for learning and hosting — ten purposeful bottles teach faster than forty trophies gathering dust while you chase the next release. Builder language helps hosts explain pours instead of apologizing for chaos when guests ask "why these?" Roles — daily, guest, learning, wild — turn random accumulation into a story guests can follow without a lecture. Budget honesty prevents shame loops where you hide cheap bottles that might be your best teachers. A shelf with roles also makes shelf intelligence and psychology tools meaningful instead of generic. Roles turn chaos into narrative — guests relax when they can tell your shelf has intent, even if the intent is humble and still learning.`,
    beginnerMisunderstanding: `Beginners think a perfect shelf looks like Instagram — rare, aligned, expensive, photographed from low angles with mood lighting. Working shelves look like notes — spills, duplicates for comparison, one embarrassing bottle that taught a lesson you still reference. Perfection is performance; coherence is stewardship. Starter track is not an insult — it is permission to learn without financing hype. Advanced and collector tracks are not mandates to spend up; they are maps if your curiosity and budget align. Embarrassing bottles belong on working shelves — they often taught the lesson that expensive mistakes never did, and stories beat aesthetics at tastings. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    realWorldExample: `You enter $300 budget honestly — not aspirational $300, real $300. Builder suggests starter trio under $100 combined plus one splurge learning bottle with a defined role, not a lottery ticket. You host a compare night with the trio instead of guarding a single allocation behind glass psychology. Friends leave educated, not intimidated; you still have budget for BiB next month. The shelf tells a story you can narrate: "these three teach mash bill, this one tests proof." Instagram gets nothing; your palate gets everything. Explain the trio roles at your next pour without apologizing for price points — confidence in intent matters more than confidence in budget.`,
    howToUse: `Pick track honestly — beginner is not a grade, it is a starting constraint. Read role labels for each suggested bottle before swapping bottles for prettier labels. Cross-check Shelf Intelligence after you log owned bottles so builder and reality align. Rebuild quarterly, not nightly — shelves should evolve with palate, not with every forum post. Swap one bottle per rebuild if budget is tight; evolution beats revolution. Photograph your shelf after each rebuild — visual memory shows drift faster than memory alone when forum hype tries to rewrite your plan. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    whatToNoticeNext: `Shelf psychology and personalities tools interpret what you built — use them after the shelf exists, not before, or you are performing identity without behavior. When builder suggestions bore you, ignore them — obsession matters more than obedience. If intel keeps flagging the same gap, builder should reflect that gap next quarter. Repeat gaps mean you are avoiding a lesson, not missing a bottle. Psychology tools get interesting only after honest logging — if results feel generic, your shelf data is probably performing instead of reporting. That is stewardship in practice — attention, context, and a pour that proves you paid both. Barrel char taught you wood matters; this page teaches you everything else around the glass matters too.`,
    rabbitHoles: [
      { label: "Shelf intelligence", href: '/bourbon/shelf-intelligence' },
      { label: "My bourbon shelf", href: '/bourbon/portfolio' },
      { label: "Compare five bottles", href: '/bourbon/compare' },
    ],
  },
  {
    id: 'shelf-intelligence',
    path: '/bourbon/shelf-intelligence',
    title: "Shelf Intelligence",
    openingNarrative: `Your shelf already talks — most people just have not learned its dialect because nobody translated logged bottles into plain language about gaps, redundancies, and missing teachers. Shelf Intelligence reads what you logged — owned, tasted, wish list, empties worth remembering — and names patterns: all wheated/no high rye, all NAS/no BiB anchor, plenty of proof/no low-proof guest pours, five versions of the same house without realizing it. It suggests next bottles with reasons attached, not affiliate spam or scores divorced from your behavior. Blind spots are framed kindly — you are not failing, you are lopsided, and lopsided palates miss half the conversation at a tasting because they cannot compare what they never bought on purpose. Think of this as a steward's audit partner that runs in seconds before you drive to the store angry about another empty Weller slot you never needed to win. Intelligence turns impulse into curriculum you chose.`,
    whyItMatters: `Strategic buying beats reactive buying — intel turns random hauls into curriculum you chose without feeling like school because each suggestion answers a gap you can taste. It prevents third wheated duplicates and forces one high-rye lesson that changes blind nights forever. Intelligence also saves face at tastings when someone asks what your shelf is trying to teach — you have an answer beyond "I like bourbon." Over time, gap closure maps palate evolution better than any quiz because behavior logged beats intentions stated. Gap language beats guilt language — intel names what is missing without shaming what you love, and that tone keeps people logging honestly month after month.`,
    beginnerMisunderstanding: `Beginners think recommendations must be expensive or allocated to count as serious next steps — forum culture trained that bias painfully. Best next bottles are often $20–$35 corrections: one BiB anchor, one high-rye daily, one wild card under $40 that tests a variable. Intel is not upsell; it is balance. If every suggestion feels pricey, you are probably logging trophies only — add staples honestly and rerun. Corrections under forty dollars often change palates forever — expensive suggestions are optional; balance is the actual recommendation hiding inside the app. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    realWorldExample: `Intel says you own five wheated bottles, zero high-rye — the graph looks like a one-note playlist. You grab Old Forester 100 instead of another Maker's variant because intel named the gap without shaming you. Next blind night you finally taste rye spice on purpose, not as accident in a cocktail. Someone asks why your shelf changed; you say you were lopsided, not that an app bossed you. That is intel working — visible learning, invisible homework. Bring intel screenshot to the store once — buying with a named gap feels adult in a hobby that often rewards impulse dressed as passion. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    howToUse: `Log honestly in My Bourbon Shelf first — garbage in, garbage out is literal here. Include tasted bottles even if you do not own them; memory matters. Read gap and next bottle sections before shopping, not after you already bought on impulse. Ignore suggestions that bore you — obsession sustains hobbies, obedience does not. Rerun after logging new bottles or finishing empties worth noting. Log empties you would buy again — they reveal true favorites better than trophies you are afraid to finish because finishing feels like losing status. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    whatToNoticeNext: `Progression chains show where your next bottle fits a ladder inside one house — combine intel with chains before splurging on top rungs you are not ready to taste against. When intel and builder disagree, trust logged behavior over hypothetical plans. If the same gap persists three months, buy the correction bottle before the next trophy — your palate is asking aloud. Persistent gaps are preferences fighting you — either buy the correction or admit you do not want that lesson yet; both answers are honest stewardship. That is stewardship in practice — attention, context, and a pour that proves you paid both. Barrel char taught you wood matters; this page teaches you everything else around the glass matters too.`,
    rabbitHoles: [
      { label: "Progression chains", href: '/bourbon/chains' },
      { label: "Shelf builder", href: '/bourbon/shelf-builder' },
      { label: "What should I buy?", href: '/bourbon/what-should-i-buy' },
    ],
  },
  {
    id: 'watchtower',
    path: '/bourbon/watchtower',
    title: "Watchtower",
    openingNarrative: `The bourbon internet is loud — release rumors, outrage threads, influencer pours that never show the failed bottles, distillery posts that say everything and nothing in the same caption. Watchtower is a weekly distillation of signals: what curiosity is rising, which bottle split the room, which producer moved culture without a press release worth reading, which argument is about to show up at your local bar whether you follow forums or not. It is not a hot take feed designed to keep you scrolling until midnight. It is a steward's scan of the horizon — the few items worth your attention before you fall into a three-hour rabbit hole that ends with cart envy and no pour. Signals link to tools — detective cases, economy, compare — so reading becomes doing, not doomscrolling. You leave with one actionable curiosity, not forty open tabs and a headache. That is the whole design — respect for your time and your palate.`,
    whyItMatters: `Attention is limited and bourbon markets exploit that limit deliberately — FOMO is a business model. Weekly signals respect your time and keep you culturally literate without living on Discord or refreshing secondary apps. You spot debates early enough to host around them, buy staples before crowds arrive, or ignore hype with confidence because you understand the incentive behind the noise. Literacy reduces anxiety — empty shelves and viral bottles feel less personal when you see the pattern before the panic. Weekly rhythm beats hourly anxiety — one signal you act on teaches more than forty signals you fear, and fear is not a palate strategy.`,
    beginnerMisunderstanding: `Beginners think trends require chasing bottles immediately or you miss the hobby entirely — as if stewardship were a stock market with only winners and losers. Most signals are about learning why a category heated, not how to win a lottery you did not need to enter. Watchtower trains judgment: learn, buy smart, or ignore — three valid outcomes. Missing a hype cycle is often success if your shelf already has teachers. Ignoring hype is often the winning move — Watchtower exists to help you choose ignore intelligently, not chase compulsively because strangers posted bottles. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    realWorldExample: `Watchtower flags BiB curiosity rising after a viral blind test embarrassed expensive NAS picks. You buy Evan Williams White before the crowd arrives locally — not to flip, to be prepared when friends ask what BiB means at your next pour. Two weeks later three people mention the same video; you already have glasses ready and a detective case link saved. You spent $25 to buy calm — cheaper than therapy, tastier than arguing online. Hosting around a signal you saw two weeks early feels like stewardship — you predicted the conversation instead of reacting to it breathlessly. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    howToUse: `Check once weekly with coffee, not hourly with anxiety. Click one signal only — the one that matches your shelf or your last frustration. Follow its linked tool to ground the signal in action: compare, case file, economy explainer. Ignore the rest guilt-free; the tower will still be here. Save signals you disagree with; disagreement is practice for hosting debates without winners. Set a recurring Sunday coffee with Watchtower — ritual turns noise into a single decision point instead of a background hum of FOMO all week. That is stewardship in practice — attention, context, and a pour that proves you paid both. Barrel char taught you wood matters; this page teaches you everything else around the glass matters too.`,
    whatToNoticeNext: `When signals match today's debate on /bourbon/today, you are seeing culture converge — good week to host a themed pour with one story and one BiB anchor. When signals repeat across weeks, a structural shift is happening — revisit economy before changing spend habits. If you never click links, switch to detective cases; passive reading alone will not stick. Repeated signals across months mean shift, not spike — adjust budget slowly and pour old staples while you learn why the category heated. That is stewardship in practice — attention, context, and a pour that proves you paid both. Barrel char taught you wood matters; this page teaches you everything else around the glass matters too.`,
    rabbitHoles: [
      { label: "What's alive today", href: '/bourbon/today' },
      { label: "Rabbit hole of the day", href: '/bourbon/rabbit-hole' },
      { label: "Bourbon economy", href: '/bourbon/economy' },
    ],
  },
  {
    id: 'chains',
    path: '/bourbon/chains',
    title: "Progression Chains",
    openingNarrative: `Random bottle collecting feels exciting for three months, then overwhelming forever — shelves become museums of impulse without a story tying bottles together. Progression chains are steward ladders inside one house: Wild Turkey 101 to Rare Breed to Russell's Reserve, Evan Williams black to white BiB to single barrel, Maker's standard to 46 to private select — each rung teaches something specific before you spend up on hype you cannot taste against anything familiar. Chains encode distiller logic: how one house scales proof, age, wood, and finishing without losing identity or becoming arbitrary price tiers. They are not mandates to spend more — they are maps for intentional curiosity. When you love a rung, you know what question the next rung answers; when you hate a rung, you stop climbing instead of buying the top out of shame. That is freedom, not upsell. Climb slow enough to taste the ladder, not the marketing.`,
    whyItMatters: `Ladders reduce buyer's remorse and comparison paralysis — you climb with purpose, not influencer momentum. Blind comparisons on a chain teach more than scattered trophy hunting because variables isolate gradually: proof before age, age before single barrel, single barrel before store pick markup. Chains also make hosting easier — you pour two rungs side by side and guests learn distiller intent without vocabulary tests. Budget respects chains when cheap rungs stay favorites forever; success is knowing where to stop, not reaching the top. Intentional rungs beat random shelves — chains give you language to explain why this bottle and not that one when both cost the same and look equally pretty.`,
    beginnerMisunderstanding: `Beginners think chains are upsell charts from brands disguised as education — cynicism earned by years of marketing. These are learning paths built from steward logic: sometimes the cheap rung stays your favorite forever and that is success, not failure to "graduate." Climbing is optional; understanding rungs is mandatory before spending up. If you cannot taste difference between rungs blind, the top rung can wait — your wallet and ego will thank you. Stopping mid-ladder is success when the stop tastes like home — chains do not measure manhood; they measure curiosity satisfied at the right price. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    realWorldExample: `You climb the Heaven Hill value chain instead of buying a random $70 bottle because a podcast said so. Each step tastes like a lesson — BiB transparency, proof lift, barrel variation — and you stop at the rung you love instead of chasing the top out of shame at a tasting. Friends ask why you skipped expensive; you say you found your answer at $25, not $90. That is chain success — intentional stop, not summit fever. Side-by-side rungs on a weeknight beat a trophy pour alone — comparison is the teacher; price is just the tuition you chose to pay. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    howToUse: `Pick one house you already enjoy enough to trust — familiarity makes differences visible. Taste current rung side-by-side with next rung if budget allows; one ounce each is enough. Log notes in portfolio so memory does not lie later. Skip rungs that do not interest you — chains are menus, not contracts. Revisit after blind league months to see if palate shifted up or down. Buy next rung only after notes on current rung exist — if you cannot describe today's bottle, tomorrow's purchase is probably performance, not learning. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    whatToNoticeNext: `Bottle progression database links individual bottles — use chains for narrative inside a house, bottles page for specs when shopping. When intel flags redundancy, check if you bought two rungs without comparing — common mistake. If every chain you try stops at BiB, you might be a value steward; own that instead of forcing prestige climbs. Value stewards who stop at BiB are not failing — they found their answer early, which is cheaper and often tastier than summit fever. That is stewardship in practice — attention, context, and a pour that proves you paid both. Barrel char taught you wood matters; this page teaches you everything else around the glass matters too.`,
    rabbitHoles: [
      { label: "Bottle progression", href: '/bourbon/bottles' },
      { label: "Compare five", href: '/bourbon/compare' },
      { label: "Blind tasting league", href: '/bourbon/league' },
    ],
  },
  {
    id: 'stories',
    path: '/bourbon/stories',
    title: "History Stories",
    openingNarrative: `Before bourbon was an asset class photographed for secondary listings, it was a survival story — frontier distillers, Prohibition criminals and clerks, cooperages burning and rebuilding, families selling names while keeping recipes, rickhouse fires that changed insurance law for everyone after. History stories here are narrative, not timelines to memorize for a test nobody administers. Pappy's myth, red wax diplomacy, medicinally legal pints, the night a warehouse collapse made news outside whiskey Twitter — each essay connects to bottles you can still buy, places you can still visit, arguments still alive on forums when someone says "they don't make it like they used to." Read when you want context that makes tasting feel like time travel — not because history replaces palate, but because history explains why labels look the way they do and why crowds care about names that taste average blind. Stories are how the hobby remembers labor, not just luxury.`,
    whyItMatters: `Stories anchor price, scarcity, and pride in human terms you can retell without sounding like a market analyst. You forgive a young NAS bottle faster when you understand why age statements vanished — supply, demand, honesty, marketing, pick your mix. Hosts who know one true story per era create emotional memory that bottles alone cannot; guests remember the Prohibition prescription tale longer than they remember proof. History also inoculates against pure hype — legends have labor behind them, but labor does not always mean better juice today. History makes labels legible — when you know why a law exists, green BiB text stops looking like decoration and starts looking like a promise worth testing.`,
    beginnerMisunderstanding: `Beginners treat history as optional trivia separate from "real" bourbon skills like tasting notes and hunting. Hosts who know one true story per era create fans faster than hosts who recite mash bills without knowing why the mash bill mattered politically or economically when it was chosen. History is a host skill, a travel skill, a detective skill — not a separate elective. You can enter through story and arrive at juice; many people do. Story-first entry is valid — many stewards arrive through narrative and learn juice later; both doors lead to the same bar if ego stays low. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    realWorldExample: `You tell the Prohibition prescription story while pouring a modern BiB — transparency law as echo of an era when labels lied by default. Guests understand why Bottled-in-Bond still matters to people who care about standards, even if they never read a statute. Politics becomes palate; standards become personal instead of preachy. Someone buys BiB that week without you recommending a brand — they recommend a idea. Story did the work; you poured the proof. Guests who buy BiB after one era story rarely need brand names — they bought transparency because you made the standard feel human, not bureaucratic. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    howToUse: `Pick one era per week — Prohibition, post-war boom, modern NAS era — instead of bingeing everything into blur. Follow story links to producer atlas and lore legends when names repeat. Pour one bottle mentioned if accessible; story attaches to muscle memory when glass is involved. Quiz yourself by retelling one story without opening the page — if you cannot, reread once, then pour. Match story era to bottle era when possible — modern NAS pours pair with modern supply debates; Prohibition tales pair with BiB anchors on the counter. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    whatToNoticeNext: `Myths quiz tests which stories became distorted — pair stories with myths page to separate fact, legend, and marketing residue. When detective cases reference the same era, read story first for emotional context, case for structural truth. If travel plans include history stops, link trail planner — miles mean more with backstory. Myths quiz after stories reveals distortion fast — what got exaggerated tells you what the culture needed to believe, which is data for hosts, not trivia. That is stewardship in practice — attention, context, and a pour that proves you paid both. Barrel char taught you wood matters; this page teaches you everything else around the glass matters too.`,
    rabbitHoles: [
      { label: "World lore", href: '/bourbon/lore' },
      { label: "Origins map", href: '/bourbon/origins' },
      { label: "Bourbon myths", href: '/bourbon/myths' },
    ],
  },
  {
    id: 'myths',
    path: '/bourbon/myths',
    title: "Bourbon Myths",
    openingNarrative: `Bourbon mythology is half the fun and half the misinformation — and telling the difference is a steward skill, not a buzzkill skill. Older must be better — until a bright young BiB wins a blind night and embarrasses a shelf of twelve-year trophies. Kentucky-only — until you taste excellent Indiana and Texas juice side by side with pride intact. Single barrel always superior — until a great batched bottle beats a mediocre pick someone overpaid for because the sticker said "select." Myths quiz and essays here are friendly arguments backed by steward logic, not smug corrections designed to win bar fights you did not need to start. The goal is not to ruin romance. It is to pour with humility while knowing which clichés waste money, which contain grains of truth worth keeping, and which exist mainly to sell wax color. Test myths in the glass, not in comments — that is where stewards agree.`,
    whyItMatters: `Myths drive bad purchases — over-aged oak bombs that taste like furniture, proof shaming that hides nuance, "smooth" talk that masks sugar and low proof without teaching vocabulary. Clearing one myth often saves $50 faster than any coupon and prevents embarrassment when a guest prefers the cheap pour blind. Myth-busting also improves hosting — you stop repeating clichés that make skeptics roll their eyes and start offering tests people can taste instead of believe. Each cleared myth buys freedom — freedom to enjoy cheap pours, to dilute without shame, to skip age worship without feeling like an impostor at tastings. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    beginnerMisunderstanding: `Beginners think myth-busting ruins romance — that learning truth kills the magic that got them curious. It usually deepens romance because reality is weirder, funnier, and more human than marketing departments allow. Prohibition stories beat slogans; DSP truth beats craft theater; blind results beat price snobbery. You can love lore and reject myths — stewards hold both without cognitive dissonance because the glass is the final judge. Romance survives truth when truth is told well — bourbon mythology is fun precisely because reality is stranger; busting myths should deepen wonder, not kill it. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    realWorldExample: `You stop avoiding NAS bottles after reading why age statements disappeared — supply chains, honesty debates, marketing games, not lazy distillers only. You discover a $22 daily pour that beats your trophy on a Tuesday when nobody is watching Instagram. You buy two more for guests instead of guarding one expensive bottle. Myth clarity freed money and anxiety; blind honesty freed palate pride. Pour NAS beside age-stated blind after reading one myth — the room learns faster in ten minutes than in ten forum threads of adjectives and ego. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    howToUse: `Take quiz first for fun with friends if possible — social stakes make memory stick. Read missed myths fully, not just correct answers — wrong answers reveal industry stories you half-knew. Argue with friends respectfully; best learning is social and slightly competitive. Pair each myth with one pour that tests it — NAS vs age stated, BiB vs mystery label, diluted vs neat high proof. Keep a myth list on your phone — when someone repeats one at a bar, invite a taste test instead of a lecture; social learning sticks better anyway. That is stewardship in practice — attention, context, and a pour that proves you paid both.`,
    whatToNoticeNext: `Detective cases often target one myth each — close cases after reading related myth so narrative and evidence align. When lab sliders contradict a myth you believed, revisit serve and expectations before blaming bottles. If you keep missing the same quiz question, you have identity tied to that myth — notice that too. Repeated quiz misses mean identity, not ignorance — notice which myth you defend emotionally and ask what purchase habit it protects before you bust it publicly. That is stewardship in practice — attention, context, and a pour that proves you paid both. Barrel char taught you wood matters; this page teaches you everything else around the glass matters too.`,
    rabbitHoles: [
      { label: "Bourbon lab", href: '/bourbon/lab' },
      { label: "BiB detective case", href: '/bourbon/detective/bib-guarantee' },
      { label: "History stories", href: '/bourbon/stories' },
    ],
  },
  {
    id: 'atlas',
    path: '/bourbon/atlas',
    title: 'The Atlas',
    openingNarrative: `Every unfamiliar word in bourbon is a doorway — mash bill, rickhouse, proof, wheated, DSP, bottled-in-bond, allocation, store pick, barrel entry proof, char, angel's share — and most glossaries treat those doors like footnotes instead of destinations. The Atlas is not a glossary. It is a map of the world: short definitions when you need speed, plain-English explanations when you need clarity, history when you need context, and forward links when you are ready to fall down a rabbit hole into lessons, tools, detective cases, producer profiles, and collection paths. Hover any linked term across Bourbon pages for a quick read; tap on mobile for a definition sheet; click through when you want the full entry with taste, buying, collecting, and culture implications spelled out like a knowledgeable friend who respects your time. Stewards do not memorize jargon — they know where jargon leads.`,
    whyItMatters: `Authority is not louder marketing — it is making industry language legible so beginners stop feeling stupid and experts stop performing. When every term links to depth, you learn faster from every page you already visit: Level 1, detective, producers, economy, lore. The Atlas turns passive reading into structured discovery — the same engine that can later power BBQ fire science, poker position theory, or country music lineage maps without rebuilding the pattern from scratch. Bourbon proves the model; other worlds inherit the machinery. Without an Atlas layer, bourbon stays a hobby app. With it, bourbon becomes a reference you trust — and trust is the moat when allocation noise and secondary hype compete for attention every week.`,
    beginnerMisunderstanding: `Beginners think glossaries are for exams — read once, forget, return to pouring. The Atlas is for living inside the hobby: hover while reading a detective case, follow a link from a producer profile, chase cousin ideas when a term sparks curiosity. You do not need to read one hundred entries sequentially. You need to know the map exists so no word on a label or forum post feels like a locked door. Another mistake is treating Atlas entries as absolute law — bourbon has sourcing games, regional variation, and marketing blur. We flag uncertain history as commonly attributed; you verify in the glass and with primary sources when stakes are high.`,
    realWorldExample: `You read a Weller thread mentioning allocation, hazmat proof, and rickhouse position — words that used to blur together. You hover allocation in a lore essay, click through to the Atlas entry, follow links to economy and the Weller detective case, and suddenly the argument is about distribution math and warehouse physics instead of mysticism. You still might not find a bottle — but you stop feeling stupid in the conversation, and you ask one sharp question at the shop instead of chasing rumors. That is authority in practice: language becomes navigation, not noise.`,
    howToUse: `Start from the index when exploring; start from inline links when reading any Bourbon page with Atlas terms highlighted. Pick one term per week tied to a bottle you own — mash bill with two pours, rickhouse with a campus map, BiB with a bonded bottle on the counter. Follow at least one forward link per entry so the graph connects in your memory, not just the definition. Use related terms and cousin ideas when building flights — they suggest comparisons you might not have planned.`,
    whatToNoticeNext: `When collector collections progress, notice which Atlas terms appear in your unlocked items — the graph ties knowledge to identity. Pair Atlas reads with blind games so vocabulary meets palate without labels. When a term repeats in three places you visit, it is calling you — read the full entry and log one tasting note using that vocabulary correctly. The Atlas is never finished; new terms appear as the industry invents new labels and markets invent new hype.`,
    rabbitHoles: [
      { label: 'Rickhouse entry', href: '/bourbon/atlas/rickhouse' },
      { label: 'Mash bill entry', href: '/bourbon/atlas/mash-bill' },
      { label: 'Producer Atlas', href: '/bourbon/producers' },
      { label: 'Detective cases', href: '/bourbon/detective' },
    ],
  },
];
